package main

import (
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"strconv"
	"strings"
	"sync"

	_ "github.com/lib/pq"
)

// readWritePin implements read-after-write consistency for accounts that have
// recently been written by this process.
//
// Rather than guessing how long replica lag might last, it records a WAL LSN
// that is known to be at or after the commit for the account's last write. A
// read for that account is served from the primary until the replica reports
// that it has replayed at least that LSN. This avoids returning a stale replica
// value when replication is delayed, while still allowing reads to move back to
// the replica once it has caught up.
type readWritePin struct {
	mu  sync.Mutex
	exp map[string]pinEntry
}

type pinEntry struct {
	lsn string
	pos uint64
}

func newReadWritePin() *readWritePin {
	return &readWritePin{exp: make(map[string]pinEntry)}
}

func (p *readWritePin) mark(account, lsn string) {
	pos, ok := parseLSN(lsn)
	if !ok {
		// If we cannot determine the LSN after a successful write, be safe and
		// keep reads for this account on the primary.
		pos = ^uint64(0)
		lsn = ""
	}

	p.mu.Lock()
	defer p.mu.Unlock()
	if cur, exists := p.exp[account]; exists && cur.pos > pos {
		return
	}
	p.exp[account] = pinEntry{lsn: lsn, pos: pos}
}

func (p *readWritePin) required(account string) (pinEntry, bool) {
	p.mu.Lock()
	defer p.mu.Unlock()
	entry, ok := p.exp[account]
	return entry, ok
}

func (p *readWritePin) clear(account string, pos uint64) {
	p.mu.Lock()
	defer p.mu.Unlock()
	if cur, ok := p.exp[account]; ok && cur.pos == pos {
		delete(p.exp, account)
	}
}

func parseLSN(lsn string) (uint64, bool) {
	parts := strings.Split(lsn, "/")
	if len(parts) != 2 {
		return 0, false
	}
	hi, err := strconv.ParseUint(parts[0], 16, 32)
	if err != nil {
		return 0, false
	}
	lo, err := strconv.ParseUint(parts[1], 16, 32)
	if err != nil {
		return 0, false
	}
	return (hi << 32) | lo, true
}

